    uint32_t batchSize = (shape.GetDimNum() >= 1) ? static_cast<uint32_t>(shape.GetDim(0)) : 1;
    uint32_t dimSize = (shape.GetDimNum() >= 2) ? static_cast<uint32_t>(shape.GetDim(1)) : 1;
    // If dim is 0, then batchSize=1, dimSize=totalLength? But we ignore.
