    // UB budget: 3 floats per element? Actually we need x, y, tmp (exp) => 3*4=12 bytes per element.
    uint32_t maxTile = 192*1024 / 12; // 16384
    maxTile = AlignDown(maxTile, 2048);
    if (maxTile < 2048) maxTile = 2048;
    uint32_t tileLen = maxTile;
    if (dimSize < tileLen) tileLen = dimSize; // no alignment needed? but keep alignment
    // We'll align down dimSize to multiple of 2048? Not necessary.

    uint32_t blockDim = batchSize;
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);
    tiling.set_batchSize(batchSize);
    tiling.set_dimSize(dimSize);
    tiling.set_dim(dim);

    tiling.SaveToBuffer(...);
