We'll write:

#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 1; // single buffer for simplicity

class KernelLogSoftmaxCustom {
public:
    __aicore__ inline KernelLogSoftmaxCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                uint32_t batchSize, uint32_t dimSize,
                                int32_t dim)
    {
        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLength);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLength);
        tileLen_ = tileLength;
        batchSize_ = batchSize;
        dimSize_ = dimSize;
        // ignore dim

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, BUFFER_NUM, tileLen_ * sizeof(float)); // for exp or max reduction
    }

    __aicore__ inline void Process()
    {
        if (dimSize_ == 0) return;

        const uint32_t blockIdx = AscendC::GetBlockIdx();
        const uint32_t blockNum = AscendC::GetBlockNum();

        // outer loop over rows with grid-stride
        for (uint32_t row = blockIdx; row < batchSize_; row += blockNum) {
            uint32_t base = row * dimSize_;
            // Phase 1: compute max over row
            float rowMax = -std::numeric_limits<float>::infinity();
            for (uint32_t t = 0; t < dimSize_; t += tileLen_) {
                uint32_t curLen = (t + tileLen_ <= dimSize_) ? tileLen_ : dimSize_ - t;
                // Load x tile
                AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
                AscendC::DataCopy(xLocal, xGm_[base + t], curLen);
                // Compute max of tile
                AscendC::LocalTensor<float> maxLocal = tmpQueue_.AllocTensor<float>();
                AscendC::VecReduceMax(maxLocal, xLocal, curLen);
                // Read scalar max
                float tileMax = maxLocal(0);
                if (tileMax > rowMax) rowMax = tileMax;
                // Free
                tmpQueue_.FreeTensor(maxLocal);
                inQueueX_.FreeTensor(xLocal);
            }

            // Phase 2: compute sum of exp(x - rowMax)
            float rowSum = 0.0f;
            for (uint32_t t = 0; t < dimSize_; t += tileLen_) {
                uint32_t curLen = (t + tileLen_ <= dimSize_) ? tileLen_ : dimSize_ - t;
                // Load x tile
                AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
                AscendC::DataCopy(xLocal, xGm_[base + t], curLen);
                // Compute x - rowMax
                AscendC::LocalTensor<float> diffLocal = tmpQueue_.AllocTensor<float>();
                AscendC::Sub(diffLocal, xLocal, rowMax, curLen);
                // Compute exp of diff
                AscendC::Exp(diffLocal, diffLocal, curLen); // reuse diffLocal for exp
                // Compute sum of exp tile
                AscendC::LocalTensor<float> sumLocal = tmpQueue_.AllocTensor<float>(); // but we already have diffLocal? We need another tensor for sum. Actually we can reuse diffLocal for sum after we have sum? Better to allocate another temporary.
                // Let's allocate a separate sum tensor of size 1
                AscendC::LocalTensor<float> sumTile = tmpQueue_.AllocTensor<float>();
                AscendC::VecReduceSum(sumTile, diffLocal, curLen);
                float tileSum = sumTile(0);
                rowSum += tileSum;
                // Free
                tmpQueue_.FreeTensor(sumTile);
                tmpQueue_.FreeTensor(diffLocal);
                inQueueX_.FreeTensor(xLocal);
            }

            // Compute log(rowSum)
            float logSum = logf(rowSum);

            // Phase 3: compute output y = x - rowMax - logSum
            for (uint32_t t = 0; t < dimSize_; t += tileLen_) {
                uint32_t curLen = (t + tileLen_ <= dimSize_) ? tileLen_ : dimSize_ - t;
                // Load x tile
                AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
                AscendC::DataCopy(xLocal, xGm_[base + t], curLen);
                // Compute x - rowMax
                AscendC::LocalTensor<float> tmpLocal = tmpQueue_.AllocTensor<float>();
                AscendC::Sub(tmpLocal, xLocal, rowMax, curLen);
                // Then subtract logSum
                AscendC::Sub(tmpLocal, tmpLocal, logSum, curLen);
                // Store to y
                AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
                AscendC::DataCopy(yLocal, tmpLocal, curLen); // not needed, we can directly assign
                // Actually we already have tmpLocal, we can copy to yLocal
                AscendC::DataCopy(yGm_[base + t], tmpLocal, curLen);
                // Free
                tmpQueue_.FreeTensor(tmpLocal);
                outQueueY_.FreeTensor(yLocal);
                inQueueX_.FreeTensor(xLocal);
            }
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, BUFFER_NUM> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t tileLen_ {0};
    uint32_t batchSize_ {0};
    uint32_t dimSize_ {0};
};

extern "C" __global__ __aicore__ void log_softmax_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelLogSoftmaxCustom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.tileLength, tiling_data.batchSize, tiling_data.dimSize, tiling_data.dim);
    op.Process();
}

